INSERT INTO `comments` VALUES (1,'미팅룩 참고했어요. 과하지 않은 게 딱 좋네요.',1,53,'2026-02-02 12:13:34',NULL),(2,'자켓 핏이 딱 단정해서 좋아요. 신뢰감 있어 보임!',1,56,'2026-02-02 12:21:34',NULL),(3,'셔츠 컬러 뭐로 입으셨어요? 톤 조합이 깔끔해요.',1,54,'2026-02-02 12:25:34',NULL),(4,'악세 최소화 공감… 저도 손목시계만 차는 편!',1,60,'2026-02-02 12:28:34',NULL),(5,'바지 기장까지 맞추면 완성도 확 올라가죠.',1,47,'2026-02-02 12:32:34',NULL),(6,'신발은 로퍼/더비 중에 뭐가 더 무난할까요?',1,58,'2026-02-02 12:36:34',NULL),(7,'출근룩에도 그대로 적용 가능해서 저장했어요!',1,44,'2026-02-02 12:40:34',NULL),(8,'톤 다운 자켓 진짜 활용도 높네요. 추천!',1,61,'2026-02-02 12:44:34',NULL),(9,'핏이 너무 과하지 않아서 더 고급져 보여요.',1,64,'2026-02-02 12:48:34',NULL),(10,'미팅 있는 날은 이런 기본기가 최고죠.',1,51,'2026-02-02 12:52:34',NULL),(11,'셔츠 카라 각 잡힌 거 진짜 중요…',1,57,'2026-02-02 12:56:34',NULL),(12,'색 조합 안정적이라 따라하기 쉽네요!',1,63,'2026-02-02 13:00:34',NULL),(13,'가방은 어떤 스타일 매치하셨나요? 서류가방? 토트?',1,55,'2026-02-02 13:05:34',NULL),(14,'디테일이 깔끔해서 사진이 더 좋아보여요.',1,59,'2026-02-02 13:10:34',NULL),(15,'이거 진짜 “면접룩”에도 되겠는데요?',1,62,'2026-02-02 13:15:34',NULL),(16,'저장했습니다. 다음에 출근룩도 기대해요!',1,52,'2026-02-02 13:21:34',NULL),(17,'출근룩은 핏이 전부… 완전 공감합니다.',14,54,'2026-01-22 08:15:34',NULL),(18,'슬랙스 기장 어디까지가 베스트라고 보세요?',14,56,'2026-01-22 08:21:34',NULL),(19,'셔츠 어깨선 맞추는 팁 더 알려주세요!',14,47,'2026-01-22 08:24:34',NULL),(20,'신발 과하지 않게 = 여기서 승부나는 듯요.',14,48,'2026-01-22 08:27:34',NULL),(21,'벨트 컬러는 보통 신발이랑 맞추시나요?',14,60,'2026-01-22 08:30:34',NULL),(22,'요즘 출근룩 너무 캐주얼해져서 고민이었는데 도움 됨!',14,58,'2026-01-22 08:34:34',NULL),(23,'셔츠는 넣입/빼입 어떤 게 더 깔끔해요?',14,55,'2026-01-22 08:38:34',NULL),(24,'슬랙스 핏 예쁘네요. 테이퍼드인가요?',14,64,'2026-01-22 08:42:34',NULL),(25,'이 조합은 진짜 실패가 없죠. 저장!',14,52,'2026-01-22 08:47:34',NULL),(26,'상체 짧은 편인데 셔츠 길이 팁도 궁금!',14,63,'2026-01-22 08:51:34',NULL),(27,'저도 출근룩은 무채색으로 가는 편이에요.',14,42,'2026-01-22 08:56:34',NULL),(28,'가방만 바꿔도 분위기 달라지더라구요.',14,61,'2026-01-22 09:01:34',NULL),(29,'코트 걸치면 바로 겨울 출근룩 완성!',14,51,'2026-01-22 09:07:34',NULL),(30,'디테일이 정리돼 있어서 사진이 더 좋아 보여요.',14,59,'2026-01-22 09:13:34',NULL),(31,'숏패딩 진짜 부해보여서 고민이었는데 도움 됐어요!',13,55,'2026-01-22 14:11:34',NULL),(32,'슬림 하의로 밸런스… 바로 적용해봄.',13,47,'2026-01-22 14:17:34',NULL),(33,'롱부츠랑 매치하면 더 예쁠 것 같아요.',13,48,'2026-01-22 14:21:34',NULL),(34,'숏패딩 색은 어떤 게 제일 무난해요?',13,63,'2026-01-22 14:25:34',NULL),(35,'비율 얘기 공감… 상의 짧으면 하의 라인이 중요하죠.',13,52,'2026-01-22 14:29:34',NULL),(36,'패딩은 신발로 정리하면 깔끔해지더라구요.',13,56,'2026-01-22 14:33:34',NULL),(37,'출근용 숏패딩도 이런 식으로 가능하겠네요!',13,45,'2026-01-22 14:38:34',NULL),(38,'와이드 하의면 너무 부해 보일까요?',13,54,'2026-01-22 14:43:34',NULL),(39,'톤온톤으로 가면 더 안정적인 느낌!',13,59,'2026-01-22 14:48:34',NULL),(40,'자켓보다 패딩은 실루엣 잡기 더 어려움…',13,62,'2026-01-22 14:53:34',NULL),(41,'이거 저장해두고 겨울에 따라할게요!',13,58,'2026-01-22 14:59:34',NULL),(42,'하의 색까지 맞추면 진짜 깔끔해 보이네요.',13,42,'2026-01-22 15:06:34',NULL),(43,'부해보임 줄이는 팁 최고… 사진도 예뻐요.',13,61,'2026-01-22 15:13:34',NULL),(44,'이너 기본 + 아우터로 승부… 깔끔해서 좋네요.',5,60,'2026-01-31 13:52:34',NULL),(45,'짧은 자켓으로 비율 잡는 거 진짜 중요하죠.',5,47,'2026-01-31 13:58:34',NULL),(46,'아우터 추천 브랜드도 궁금해요!',5,55,'2026-01-31 14:03:34',NULL),(47,'이 조합은 출근에도 데이트에도 되겠네요.',5,54,'2026-01-31 14:08:34',NULL),(48,'컬러가 안정적이라 따라하기 쉬움!',5,42,'2026-01-31 14:14:34',NULL),(49,'신발까지 맞추면 더 완성도 올라갈 듯요.',5,48,'2026-01-31 14:19:34',NULL),(50,'아우터만 바꿔도 사진 느낌이 바뀌네요.',5,64,'2026-01-31 14:25:34',NULL),(51,'저장! 다음엔 코트 버전도 보고 싶어요.',5,61,'2026-01-31 14:31:34',NULL),(52,'핏이 깔끔해서 더 고급져 보여요.',5,56,'2026-01-31 14:37:34',NULL),(53,'이너를 어디까지 심플하게 가야할지 감 잡힘!',5,59,'2026-01-31 14:43:34',NULL),(54,'자켓 길이 선택 팁 더 있나요?',5,63,'2026-01-31 14:49:34',NULL),(55,'사진 구도도 깔끔해서 더 좋아보여요.',5,58,'2026-01-31 14:55:34',NULL),(56,'소재 믹스가 핵심이라는 말 완전 공감!',2,51,'2026-02-02 09:04:34',NULL),(57,'올블랙은 진짜 질감 차이로 살아나요.',2,56,'2026-02-02 09:09:34',NULL),(58,'가죽/니트 조합 좋아요. 과하지 않게 포인트.',2,62,'2026-02-02 09:15:34',NULL),(59,'신발은 블랙으로 통일 vs 화이트 포인트 뭐가 더 좋나요?',2,48,'2026-02-02 09:20:34',NULL),(60,'악세 하나만 더해도 느낌 확 달라질 듯!',2,59,'2026-02-02 09:26:34',NULL),(61,'올블랙 처음 도전하는 사람에게 추천할만한 조합 같아요.',2,55,'2026-02-02 09:32:34',NULL),(62,'사진이 딱 미니멀하게 예뻐요.',2,64,'2026-02-02 09:38:34',NULL),(63,'코트랑 매치하면 겨울에도 멋있겠네요.',2,61,'2026-02-02 09:45:34',NULL),(64,'가죽 비율이 너무 많으면 부담인데 딱 적당!',2,63,'2026-02-02 09:53:34',NULL),(65,'저장했습니다. 다음엔 올그레이도 보고 싶어요.',2,54,'2026-02-02 10:01:34',NULL),(66,'올블랙은 실패 없어서 좋아요.',2,42,'2026-02-02 10:08:34',NULL),(67,'3색만 돌려도 충분하다는 말 완전 맞아요.',15,60,'2026-01-21 11:13:34',NULL),(68,'아이보리 비중 늘리면 확 부드러워지더라구요.',15,63,'2026-01-21 11:18:34',NULL),(69,'그레이 톤을 어디까지 밝게 쓰는지 궁금!',15,55,'2026-01-21 11:23:34',NULL),(70,'무채색은 신발만 깨끗해도 성공 느낌.',15,48,'2026-01-21 11:28:34',NULL),(71,'출근룩/데이트룩 둘 다 가능해서 좋네요.',15,54,'2026-01-21 11:34:34',NULL),(72,'미니멀 좋아하는 사람한테 최고 조합.',15,49,'2026-01-21 11:41:34',NULL),(73,'가방이나 시계로만 포인트 주면 딱일 듯!',15,59,'2026-01-21 11:48:34',NULL),(74,'저장해두고 옷장 색깔 정리해야겠어요.',15,58,'2026-01-21 11:56:34',NULL),(75,'블랙 비중이 너무 높으면 답답한데 밸런스 좋네요.',15,56,'2026-01-21 12:04:34',NULL),(76,'사진이 심플해서 더 예뻐 보임!',15,64,'2026-01-21 12:13:34',NULL),(77,'무채색 기본기 제대로네요. 굿!',15,42,'2026-01-21 12:21:34',NULL),(78,'“로고보다 실루엣” 이 말 저장…',8,54,'2026-01-28 13:07:34',NULL),(79,'주름 적은 소재 진짜 중요하죠. 관리도 쉬움.',8,56,'2026-01-28 13:14:34',NULL),(80,'미니멀은 핏이 다라서 수선 필수 공감!',8,47,'2026-01-28 13:20:34',NULL),(81,'색은 2~3개로 끝내는 게 제일 깔끔.',8,42,'2026-01-28 13:26:34',NULL),(82,'신발까지 깨끗하면 완성도 진짜 올라가요.',8,48,'2026-01-28 13:33:34',NULL),(83,'가방도 로고 적은 걸로 맞추면 더 좋더라구요.',8,52,'2026-01-28 13:40:34',NULL),(84,'사진에서 라인이 정리돼 보여서 더 미니멀해요.',8,64,'2026-01-28 13:48:34',NULL),(85,'미니멀 어렵게 생각했는데 기준 잡힘!',8,55,'2026-01-28 13:56:34',NULL),(86,'저도 무채색 위주라 참고했습니다.',8,49,'2026-01-28 14:04:34',NULL),(87,'이런 글 더 자주 올려주세요!',8,58,'2026-01-28 14:12:34',NULL),(88,'톤온톤은 겨울에 진짜 최고… 따뜻해 보이기도 함!',3,61,'2026-02-01 13:13:34',NULL),(89,'이너 얇게 입는 팁 유용해요. 레이어드 덜 답답!',3,46,'2026-02-01 13:21:34',NULL),(90,'머플러 컬러를 코트랑 맞추는 게 포인트네요.',3,59,'2026-02-01 13:29:34',NULL),(91,'코트 길이 선택 기준도 궁금해요!',3,55,'2026-02-01 13:37:34',NULL),(92,'신발까지 톤 맞추면 완전 깔끔할 듯.',3,48,'2026-02-01 13:45:34',NULL),(93,'롱코트는 진짜 “한 벌로 끝” 느낌이라 좋아요.',3,51,'2026-02-01 13:53:34',NULL),(94,'겨울코디장인 닉값하네요… 저장!',3,54,'2026-02-01 14:01:34',NULL),(95,'톤온톤은 사진도 예쁘게 나오는 듯요.',3,64,'2026-02-01 14:09:34',NULL),(96,'이런 코디는 출근에도 가능해서 좋아요.',3,45,'2026-02