INSERT INTO `looks` VALUES (4,'2026-01-02',NULL,21,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/9afc0b0a-4b30-42bf-9446-5751dacaaf77-result.png','2026-01-30 09:07:35'),(5,'2026-02-01',NULL,21,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/d2204eff-ddbb-4086-8d09-14299247b131-result.png','2026-01-30 10:09:35'),(6,'2026-02-16','~와 같은 이유로 추천합니다.',21,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/d2204eff-ddbb-4086-8d09-14299247b131-result.png','2026-01-30 10:12:31'),(7,'2026-03-20',NULL,21,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/3f713b58-d404-4ae2-81b0-6b4eb5b964f2-result.png','2026-01-30 17:32:18'),(21,'2026-02-09','모던하면서도 차가운 도시의 감성을 담기 위해 블랙과 그레이, 그리고 딥한 컬러감을 활용한 세련된 미니멀 룩을 제안합니다. 한겨울의 추위에도 스타일을 놓치지 않도록 보온성이 뛰어난 딥 그린 브이넥 니트와 실루엣이 정갈한 블랙 롱 코트를 매치했습니다. 하의는 깔끔한 핏의 슬랙스를 선택하여 지적인 분위기를 강조했으며, 전체적인 톤을 맞춰주는 블랙 레더 슈즈로 마무리하여 전문적이고 도회적인 겨울 스타일링을 완성했습니다.',17,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/548104f1-6f25-4a90-8ed4-351a8eb8f374-result.png','2026-02-04 10:16:42'),(22,'2026-02-13','깊고 진한 인디고 컬러가 주는 특유의 단정하면서도 묵직한 분위기를 겨울 시즌에 맞게 재해석했습니다. 데님 셔츠의 견고한 느낌을 대신해 보온성이 뛰어난 다크 그린 컬러의 브이넥 니트를 선택하였고, 여기에 차분한 브라운 톤의 와이드 슬랙스를 매치하여 세련된 컬러 밸런스를 완성했습니다. 마지막으로 직선적인 실루엣의 블랙 코트를 레이어드하여, 추운 날씨에도 스타일의 중심을 잃지 않는 미니멀한 윈터 룩을 제안합니다.',17,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/02cf9bfd-03ac-4646-8267-2f1ce5d4dcca-result.png','2026-02-04 13:20:26'),(23,NULL,NULL,17,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/bdda77c5-55fd-4999-8b41-ec7a11bf6f2b-result.png','2026-02-04 13:21:50'),(24,'2026-02-05',NULL,17,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/965b73c3-a978-4061-9b66-910b37671565-result.png','2026-02-04 13:23:31'),(29,'2026-02-01',NULL,65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/ca6a69e2-e426-461e-89c0-e78e00bb46b3-result.png','2026-02-06 10:20:53'),(30,'2026-02-17',NULL,67,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/00dc1d7f-f989-4248-945e-46a3deb73933-result.png','2026-02-06 10:25:04'),(31,'2026-02-20',NULL,67,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/4c11477f-0271-43f8-9fc2-875a73f8a008-result.png','2026-02-06 10:25:53'),(32,'2026-02-04',NULL,65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/5a7c948a-2ee8-49d6-9bb5-7393c2e584c7-result.png','2026-02-06 10:26:42'),(33,'2026-02-11','전체적으로 차분한 뉴트럴 톤을 베이스로 하여 세련되면서도 따뜻한 분위기의 윈터 룩을 연출했습니다. 보온성이 뛰어난 집업 니트와 부드러운 색감의 슬랙스를 매치하여 깔끔한 실루엣을 유지했고, 여기에 블랙 컬러의 숏패딩을 더해 도심 속에서도 활동적인 무드를 느낄 수 있도록 구성했습니다. 자칫 단조로울 수 있는 코디에 톤온톤 머플러를 레이어드하여 겨울철 머스트해브 스타일링을 완성했으며, 블랙 백팩과 스니커즈로 마무리하여 시크한 포인트를 주었습니다.',67,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/77d6d809-fb7d-445b-842a-a992ce3fb391-result.png','2026-02-06 10:27:44'),(34,'2026-02-10',NULL,67,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/ff4504bc-7528-4af7-987e-b0326f0726a5-result.png','2026-02-06 10:28:51'),(35,NULL,NULL,65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/e4357ba4-3127-4f38-b3bf-7593910292b8-result.png','2026-02-06 10:29:44'),(36,'2026-02-02',NULL,65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/8dc68489-a7cd-4abb-8496-58ce3ca7c2d6-result.png','2026-02-06 10:31:32'),(37,'2026-02-09',NULL,67,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/3bd6ebdf-207a-4b11-a989-c85ea2303a1b-result.png','2026-02-06 10:31:59'),(38,'2026-02-05',NULL,65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/3716d473-ee1a-4c8e-bbcb-2e6a002a15fc-result.png','2026-02-06 10:48:23'),(39,'2026-01-27',NULL,65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/0a85347d-91ef-4b7c-ab9a-22256c163345-result.png','2026-02-06 10:51:14'),(40,'2026-02-03',NULL,65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/614b9454-cac2-4f46-b7a7-1588acd62f76-result.png','2026-02-06 11:33:11'),(41,'2026-01-28',NULL,65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/3475a34b-3959-4066-b4ad-1f1ffd885e3d-result.png','2026-02-06 11:35:38'),(42,'2026-01-30',NULL,65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/79519481-605e-4808-9c8d-dcf98d0059cc-result.png','2026-02-06 11:36:21'),(43,'2026-02-03','세련되면서도 도시적인 무드를 유지하며 추운 겨울 날씨에 완벽하게 대응할 수 있는 스타일링입니다. 메인 아이템으로 선택한 토프 컬러의 집업 니트는 특유의 차분하고 고급스러운 색감을 잘 전달하며, 여기에 보온성이 뛰어난 블랙 숏패딩을 매치하여 실용적인 겨울 룩을 완성했습니다. 깔끔한 그레이 슬랙스와 스니커즈의 조합은 활동성을 챙기면서도 단정한 실루엣을 유지해주고, 포근한 머플러를 더해 따뜻함과 스타일의 완성도를 동시에 높인 스마트 캐주얼 룩을 연출했습니다.',67,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/7f44caa4-5719-4aed-84a7-83cb6074a8a6-result.png','2026-02-06 12:25:26'),(44,NULL,NULL,67,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/96608f65-9129-48a8-822b-7d23a1759682-result.png','2026-02-06 12:29:17'),(46,NULL,'추운 겨울 날씨에도 밝고 화사한 분위기를 유지할 수 있도록 아이보리 숏 패딩과 베이지 톤의 하프 집업 니트를 조합했습니다. 상의의 부드러운 컬러감과 조화를 이루는 워싱 데님을 매치해 캐주얼하면서도 정돈된 무드를 연출했으며, 톤온톤 머플러로 보온성을 더했습니다. 전체적인 실루엣을 잡아주는 볼륨 있는 스니커즈와 깔끔한 백팩을 더해 데일리하면서도 세련된 윈터 룩을 제안합니다.',65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/034f4be2-f083-4657-9d8d-486f8ad93492-result.png','2026-02-06 12:57:18'),(47,NULL,'겨울철 차분하면서도 화사한 분위기를 연출하기 위해 아이보리 톤의 푸퍼 패딩과 베이지 컬러의 하프 집업 니트를 매치했습니다. 전체적인 컬러 밸런스를 고려해 중청 데님 팬츠로 캐주얼한 감성을 더했으며, 보온성을 높여주는 뉴트럴 톤의 머플러와 실용적인 메신저 백을 조합해 세련된 데일리 윈터 룩을 완성했습니다.',65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/bdf1df8d-111a-4734-af6c-d5dddde86b70-result.png','2026-02-06 13:07:23'),(48,NULL,NULL,65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/9c32f4b9-fb38-4cb4-a693-7f7f04a74e39-result.png','2026-02-06 13:19:19'),(49,NULL,'전체적으로 부드러운 베이지와 화이트 톤을 베이스로 하여, 깔끔하면서도 지적인 미니멀 캐주얼 무드를 완성했습니다. 추운 겨울 날씨에 대비해 보온성이 우수한 헤비 게이지의 반집업 니트와 계절감이 돋보이는 코듀로이 팬츠를 매치하였으며, 여기에 볼륨감 있는 패딩과 톤온톤 머플러를 레이어드하여 포근하면서도 입체적인 실루엣을 연출했습니다. 자칫 단조로울 수 있는 밝은 톤의 배색에 블랙 컬러의 메신저 백으로 중심을 잡아주어 안정감과 활동성을 동시에 챙긴 세련된 데일리 룩입니다.',65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/a80da98f-9d0f-4091-8b18-84cd801ea493-result.png','2026-02-06 13:26:07'),(50,'2026-01-23',NULL,65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/35682878-5e9a-4a4f-8cab-f830d8dc94db-result.png','2026-02-06 13:33:30'),(51,NULL,'전체적으로 차분하고 따뜻한 베이지와 화이트 톤을 메인으로 활용하여 깔끔한 겨울 데일리 룩을 구성했습니다. 보온성이 뛰어난 베이지 컬러의 하프 집업 니트와 화이트 패딩의 조합은 포근하면서도 정돈된 인상을 주며, 여기에 자연스러운 워싱의 데님 팬츠를 매치해 활동성을 더했습니다. 마무리로 톤온톤의 머플러와 세련된 블랙 백팩을 선택하여 계절감에 완벽히 어울리는 스타일리시한 무드를 완성했습니다.',65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/854c7c74-6be5-497f-818b-911810faf50a-result.png','2026-02-06 13:40:45'),(73,NULL,'세련된 무드를 유지하면서도 겨울의 추위에 대비할 수 있는 미니멀 시크 룩을 제안해 드립니다. 묵직한 무게감의 블랙 코트와 부드러운 크림 톤의 상의를 매치하여 정갈한 색감 조화를 이루었으며, 와이드한 블랙 팬츠로 시크한 실루엣을 완성했습니다. 여기에 보온성을 더해줄 비니와 깔끔한 블랙 백을 곁들여, 도시적인 세련미와 실용성을 모두 갖춘 완벽한 겨울 코디입니다.',1,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/90b3c01b-0c38-43ce-820f-806985e53cde-result.png','2026-02-06 18:06:29'),(74,NULL,NULL,1,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/46714d6e-24a5-4595-9133-471fe1ddc726-result.png','2026-02-06 18:07:35'),(75,'2026-01-31',NULL,65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/c41d4a25-e25c-4e1e-b434-8600c42a4605-result.png','2026-02-07 00:11:36'),(76,'2026-01-24',NULL,65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/9f92064c-b831-44a5-be5a-cc475acfbd02-result.png','2026-02-07 00:13:26'),(77,'2026-02-06',NULL,65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/fd5ffeee-8772-44dd-853b-7a7308a82120-result.png','2026-02-07 00:17:15'),(78,'2026-02-07',NULL,65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/8b37a513-9124-43de-947e-c64eaae34304-result.png','2026-02-07 00:19:51'),(79,'2026-02-09',NULL,65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/0846d107-08ad-49d8-9547-c2cb12b2810d-result.png','2026-02-07 00:23:41'),(80,'2026-01-29',NULL,65,'https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/7d6e3b48-73fe-405d-bd0c-46d3aee503dd-result.png','2026-02-07 00:26:05'),(81,'2026-01-26',NULL,65,'https://clo