INSERT INTO `posts` VALUES (1,'미팅 있는 날 자켓룩','https://images.unsplash.com/photo-1588011025378-15f4778d2558?w=900&auto=format&fit=crop&q=60&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxzZWFyY2h8Mzd8fCVFQyU5RSU5MCVFQyVCQyU5MyUyMCVFQyVCRCU5NCVFQiU5NCU5NHxlbnwwfHwwfHx8Mg%3D%3D','톤 다운 자켓+단정한 셔츠로 신뢰감. 악세는 최소로 정리.',714,45,'2026-02-02 12:03:34',NULL),(2,'올블랙 소재믹스','https://images.unsplash.com/photo-1737020383362-1bff76fde9f6?q=80&w=987&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','올블랙은 소재 차이로 살아나요. 니트/코튼/가죽 질감 섞어서 심심함 방지.',438,42,'2026-02-02 08:53:34',NULL),(3,'롱코트+머플러 톤온톤','https://images.unsplash.com/photo-1760551937138-6025e3304e69?q=80&w=987&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','겨울엔 톤온톤이 정답. 이너는 얇게, 코트와 머플러로 보온+핏 둘 다!',531,43,'2026-02-01 13:03:34',NULL),(4,'컬러 포인트 하나만','https://images.unsplash.com/photo-1646178955950-6d787530657c?q=80&w=1064&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','색을 많이 쓰기보다 포인트 1개만 두면 훨씬 세련돼요.',437,50,'2026-02-01 08:03:34',NULL),(5,'아우터로 코디 끝내기','https://images.unsplash.com/photo-1760551733340-a70825258486?q=80&w=987&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','이너는 기본, 아우터로 분위기 결정. 오늘은 짧은 자켓으로 비율 잡았어요.',529,51,'2026-01-31 13:43:34',NULL),(6,'꾸안꾸는 신발이 70%','https://images.unsplash.com/photo-1544037812-7aabb2eb7801?q=80&w=2093&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','기본템이면 신발/가방 하나로 분위기가 갈려요. 포인트는 하나만!',354,44,'2026-01-31 10:03:34',NULL),(7,'바지 기장 1cm의 차이','https://images.unsplash.com/photo-1713268527421-44e7ce8b91d4?w=900&auto=format&fit=crop&q=60&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxzZWFyY2h8MjB8fCVFQiVCMCU5NCVFQyVBNyU4MCUyMCVFQSVCOCVCMCVFQyU5RSVBNXxlbnwwfHwwfHx8Mg%3D%3D','기장 맞추면 다리 라인이 바뀝니다. 수선은 무조건 추천.',266,47,'2026-01-29 11:03:34',NULL),(8,'미니멀 룩의 핵심','https://images.unsplash.com/photo-1759229874914-c1ffdb3ebd0c?q=80&w=1674&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','미니멀은 로고보다 실루엣. 주름 적은 소재 + 단정한 라인 추천.',345,49,'2026-01-28 12:58:34',NULL),(9,'주말 산책룩 추천','https://images.unsplash.com/photo-1630911014497-63b41126accb?q=80&w=987&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','편한데 대충은 아닌 느낌. 톤은 차분하게, 실루엣은 여유 있게!',150,52,'2026-01-28 07:03:34',NULL),(10,'레이어드 실패 줄이는 법','https://images.unsplash.com/photo-1642229105108-8263fbb298a7?q=80&w=1064&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','레이어드는 길이 차이만 지켜도 정리돼요. 이너 짧게, 아우터 길게!',242,46,'2026-01-27 12:03:34',NULL),(11,'신발 톤 맞추는 팁','https://images.unsplash.com/photo-1625178494269-c91109fcc711?q=80&w=1015&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','상의/하의가 무난하면 신발 톤을 맞추는 게 가장 쉬운 정리법이에요.',322,48,'2026-01-26 09:03:34',NULL),(12,'데님톤 통일 코디','https://images.unsplash.com/photo-1590805566348-4100a9ddba41?q=80&w=987&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','상하의 톤만 맞춰도 데님은 실패 확률이 확 내려가요. 신발은 화이트로 정리!',120,41,'2026-01-25 13:03:34',NULL),(13,'패딩 부해보임 줄이기','https://images.unsplash.com/photo-1629374029669-aab2f060553b?q=80&w=987&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','숏패딩은 하의 실루엣이 중요. 슬림한 하의로 밸런스 맞추면 부해보임↓',314,43,'2026-01-22 14:03:34',NULL),(14,'셔츠+슬랙스 출근룩','https://images.unsplash.com/photo-1584864783592-f1d6d4fcd1d0?q=80&w=987&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','출근룩은 핏이 전부. 셔츠는 어깨, 슬랙스는 기장, 신발은 과하지 않게.',454,45,'2026-01-22 08:03:34',NULL),(15,'무채색 조합 추천','https://images.unsplash.com/photo-1734203313724-f218673cdca8?q=80&w=987&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','블랙/그레이/아이보리 3색만 돌려도 충분히 다양해요.',456,49,'2026-01-21 11:03:34',NULL),(16,'밝은색 어렵지 않게','https://images.unsplash.com/photo-1674823865199-a08583e473c5?q=80&w=1064&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','밝은색은 하의로 깔면 부담이 줄어요. 상의는 뉴트럴로!',292,50,'2026-01-20 09:03:34',NULL),(17,'자켓 vs 코트 선택','https://images.unsplash.com/photo-1642174916136-e7d9247ffa1e?q=80&w=987&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','바람 강한 날엔 코트, 이동 많은 날엔 자켓. 상황에 따라 골라요.',373,51,'2026-01-19 13:03:34',NULL),(18,'청바지 하나로 2코디','https://images.unsplash.com/photo-1509003124559-eb6678fe452b?q=80&w=1770&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','청바지는 상의만 바꿔도 느낌이 확 바뀌어요. 캐주얼/출근 2가지로!',289,41,'2026-01-18 10:03:34',NULL),(19,'상의 핏 잡는 꿀팁','https://images.unsplash.com/photo-1632129460818-7e7fb9603a53?q=80&w=999&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','어깨선 맞추면 반은 먹고 들어가요. 너무 오버하면 정리 어려움.',303,47,'2026-01-14 12:03:34',NULL),(20,'레이어드 색조합','https://images.unsplash.com/photo-1766953266126-a786b5854692?q=80&w=1769&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','레이어드할 때는 바탕색 2개+포인트 1개가 깔끔해요.',214,46,'2026-01-12 09:03:34',NULL),(21,'신발 관리도 코디','https://images.unsplash.com/photo-1614413328878-a56d9e448f40?q=80&w=1770&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','신발이 깨끗하면 같은 옷도 더 깔끔해 보여요. 관리 루틴 공유!',208,48,'2026-01-10 11:03:34',NULL),(22,'가방 하나로 포인트','https://images.unsplash.com/photo-1632282004709-98206cfa8452?q=80&w=987&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','옷이 무난하면 가방으로 포인트 주기. 색은 1개만!',294,52,'2026-01-07 13:03:34',NULL),(26,'제목','https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/a6d6c571-be05-44c2-af05-b8185a088b46-upload_1770272740308.jpg','테스트',13,66,'2026-02-05 15:25:41','2026-02-05 15:26:16'),(27,'옷 잘 입고 싶어요!','https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/7fe3e938-0c35-4622-b40c-280474aa6a0b-upload_1770307735499.jpg','오늘 처음 이용해봐요!',25,67,'2026-02-06 01:08:55',NULL),(28,'저 못생긴 것 같아요 ㅠㅠ','https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/40acd01b-3c67-4e38-96bb-418ccecf9c54-upload_1770307904889.jpg','그렇죠??',29,67,'2026-02-06 01:11:45',NULL),(29,'AI 추천룩이에요!','https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/7ba16725-0576-4407-b2ef-034647d0b339-upload_1770349023460.jpg','ai가 추천해줬어요!',29,67,'2026-02-06 12:37:04',NULL),(30,'패완얼','https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/5ee3747e-983c-43b9-8587-ad25f0f76c34-upload_1770349150219.jpg','패션앱 필요없다. 얼굴이 중요하다 ㅠ',22,67,'2026-02-06 12:39:11',NULL),(31,'이렇게 입어도...','https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/fd8ea2a0-4231-463a-b7e8-5facf5ca629b-upload_1770349243391.jpg','말이 안된다',37,67,'2026-02-06 12:40:44',NULL),(32,'제 싸피 출근룩 어때요?','https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/f53b2dce-226a-4374-aa5e-cb4970d3b24d-upload_1770349580911.jpg','싸피 베스트 멤버의 룩!',108,65,'2026-02-06 12:46:22',NULL),(33,'너너너','https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/0d579294-c74e-464e-8561-83b91661447b-upload_1770351278272.jpg','어엉엉',40,65,'2026-02-06 13:14:39','2026-02-07 00:54:53'),(34,'7eye','https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/de15e32b-112b-456a-9e4d-8065313a12a6-upload_1770362540193.jpg','esdd',4,16,'2026-02-06 16:22:21','2026-02-06 16:22:31'),(35,'첸 공항 룩 미쳤다~~~','https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/fc2c27d7-6a41-4bd6-b4f5-5a55c053f467-upload_1770445391154.jpg','첸 공항 룩 너무 멋져요~',112,1,'2026-02-07 15:23:13',NULL),(36,'프로필 사진에 찍은 룩 어때요?','https://closetory-s3.s3.ap-northeast-2.amazonaws.com/images/c9929cda-ac36-4f6f-aebd-c4803e8d526e-upload_1770448665941.jpg','기분 전환으로 프로필 사진 찍어 봤는데 어떤가요?',7,70,'2026-02-07 16:17:47',NULL),(37,'소개팅 가는데 어때요?','https://closetory-s3.s3.ap-northeast-2.amazonaws.co